# -*- coding: utf-8 -*-
"""Mustaqillik davri tarixi - 10 mavzu konspekt generatori."""
import zipfile, datetime
TOPICS = []
def esc(t): return t.replace("&","&amp;").replace("<","&lt;").replace(">","&gt;").replace('"',"&quot;")
def run(text,bold=False,size=28,font="Times New Roman"):
    rpr='<w:rPr><w:rFonts w:ascii="%s" w:hAnsi="%s" w:cs="%s"/>'%(font,font,font)
    if bold: rpr+='<w:b/><w:bCs/>'
    rpr+='<w:sz w:val="%d"/><w:szCs w:val="%d"/></w:rPr>'%(size,size)
    return '<w:r>%s<w:t xml:space="preserve">%s</w:t></w:r>'%(rpr,esc(text))
def para(text,bold=False,size=28,align="both",indent_first=709,space_after=120,line=360,keep_next=False):
    ppr='<w:pPr>'
    if keep_next: ppr+='<w:keepNext/>'
    ppr+='<w:spacing w:after="%d" w:line="%d" w:lineRule="auto"/>'%(space_after,line)
    if indent_first: ppr+='<w:ind w:firstLine="%d"/>'%indent_first
    ppr+='<w:jc w:val="%s"/></w:pPr>'%align
    return '<w:p>%s%s</w:p>'%(ppr,run(text,bold=bold,size=size))
def page_break(): return '<w:p><w:r><w:br w:type="page"/></w:r></w:p>'
def empty_para(): return '<w:p><w:pPr><w:spacing w:after="0" w:line="360" w:lineRule="auto"/></w:pPr></w:p>'
def build_topic(t,is_first):
    parts=[]
    if not is_first: parts.append(page_break())
    parts.append(para("%d-MAVZU. %s"%(t["num"],t["title"].upper()),bold=True,size=30,align="center",indent_first=0,space_after=180,keep_next=True))
    parts.append(para("Reja:",bold=True,size=28,align="left",indent_first=0,space_after=60,keep_next=True))
    for i,r in enumerate(t["reja"],1): parts.append(para("%d. %s"%(i,r),size=28,align="left",indent_first=360,space_after=40))
    parts.append(empty_para())
    for idx,(head,paras) in enumerate(t["sections"],1):
        parts.append(para("%d. %s"%(idx,head),bold=True,size=28,align="left",indent_first=0,space_after=80,keep_next=True))
        for p in paras: parts.append(para(p,size=28,align="both",indent_first=709,space_after=120))
    return "".join(parts)
def build_document():
    body="".join(build_topic(t,i==0) for i,t in enumerate(TOPICS))
    sect='<w:sectPr><w:pgSz w:w="11906" w:h="16838"/><w:pgMar w:top="1134" w:right="850" w:bottom="1134" w:left="1701" w:header="708" w:footer="708" w:gutter="0"/><w:pgNumType w:start="1"/></w:sectPr>'
    return '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships"><w:body>'+body+sect+'</w:body></w:document>'
CT='<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/><Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/><Override PartName="/word/styles.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"/><Override PartName="/docProps/core.xml" ContentType="application/vnd.openxmlformats-package.core-properties+xml"/><Override PartName="/docProps/app.xml" ContentType="application/vnd.openxmlformats-officedocument.extended-properties+xml"/></Types>'
RE='<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/><Relationship Id="rId2" Type="http://schemas.openxmlformats.org/package/2006/relationships/metadata/core-properties" Target="docProps/core.xml"/><Relationship Id="rId3" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/extended-properties" Target="docProps/app.xml"/></Relationships>'
DR='<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles" Target="styles.xml"/></Relationships>'
ST='<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:docDefaults><w:rPrDefault><w:rPr><w:rFonts w:ascii="Times New Roman" w:hAnsi="Times New Roman" w:cs="Times New Roman"/><w:sz w:val="28"/><w:szCs w:val="28"/><w:lang w:val="uz-Latn-UZ"/></w:rPr></w:rPrDefault><w:pPrDefault><w:pPr><w:spacing w:line="360" w:lineRule="auto"/></w:pPr></w:pPrDefault></w:docDefaults><w:style w:type="paragraph" w:default="1" w:styleId="Normal"><w:name w:val="Normal"/><w:rPr><w:rFonts w:ascii="Times New Roman" w:hAnsi="Times New Roman" w:cs="Times New Roman"/><w:sz w:val="28"/><w:szCs w:val="28"/></w:rPr></w:style></w:styles>'
def cp():
    n=datetime.datetime.utcnow().strftime("%Y-%m-%dT%H:%M:%SZ")
    return '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<cp:coreProperties xmlns:cp="http://schemas.openxmlformats.org/package/2006/metadata/core-properties" xmlns:dc="http://purl.org/dc/elements/1.1/" xmlns:dcterms="http://purl.org/dc/terms/" xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance"><dc:title>Mustaqillik davri tarixi</dc:title><dc:creator>Konspekt generatori</dc:creator><dcterms:created xsi:type="dcterms:W3CDTF">%s</dcterms:created><dcterms:modified xsi:type="dcterms:W3CDTF">%s</dcterms:modified></cp:coreProperties>'%(n,n)
AP='<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<Properties xmlns="http://schemas.openxmlformats.org/officeDocument/2006/extended-properties"><Application>Konspekt generatori</Application></Properties>'
def write_docx(path):
    with zipfile.ZipFile(path,"w",zipfile.ZIP_DEFLATED) as z:
        z.writestr("[Content_Types].xml",CT); z.writestr("_rels/.rels",RE)
        z.writestr("word/document.xml",build_document()); z.writestr("word/_rels/document.xml.rels",DR)
        z.writestr("word/styles.xml",ST); z.writestr("docProps/core.xml",cp()); z.writestr("docProps/app.xml",AP)
    print("Yaratildi:",path); print("Mavzular soni:",len(TOPICS))

TOPICS.append({"num":1,"title":"Mustaqillik davri va istiqlol hamda taraqqiyot yo'li","reja":["O'zbekiston mustaqilligining e'lon qilinishi va tarixiy ahamiyati.","Mustaqillik davrining dastlabki qadamlari va qiyinchiliklari.","Taraqqiyot yo'lining asosiy tamoyillari.","Mustaqillikning xalqaro tan olinishi."],"sections":[("O'zbekiston mustaqilligining e'lon qilinishi va tarixiy ahamiyati",["1991-yil 31-avgustda O'zbekiston Respublikasi Oliy Kengashi mamlakatning davlat mustaqilligini e'lon qildi. 1991-yil 1-sentabr O'zbekiston Respublikasining Mustaqillik kuni deb belgilandi. Bu tarixiy voqea o'zbek xalqining ko'p asrlik davlatchilik an'analarining tiklanishi bo'ldi.","Mustaqillikning e'lon qilinishi xalqimiz uchun o'z taqdirini o'zi belgilash, milliy qadriyatlarni tiklash va jahon hamjamiyatida teng huquqli davlat sifatida o'z o'rnini egallash imkoniyatini yaratdi. Bu hodisa nafaqat siyosiy, balki ma'naviy-ruhiy jihatdan ham buyuk ahamiyatga ega bo'ldi.","1991-yil 29-dekabrda o'tkazilgan umumxalq referendumida fuqarolarning 98,2 foizi mustaqillikni qo'llab-quvvatladi. Shu kunning o'zida birinchi Prezident saylovi bo'lib o'tdi. Bu demokratik jarayonlar yosh davlatning qonuniy asoslarini mustahkamladi."]),("Mustaqillik davrining dastlabki qadamlari va qiyinchiliklari",["Mustaqillikning dastlabki yillarida O'zbekiston bir qator jiddiy muammolarga duch keldi: sobiq ittifoq parchalanishidan kelib chiqqan iqtisodiy inqiroz, inflyatsiya, ishsizlik, ijtimoiy beqarorlik va mintaqaviy ziddiyatlar. Bu qiyinchiliklarni bartaraf etish katta iroda va strategik fikrlashni talab qildi.","Dastlabki qadamlar sifatida milliy valyuta — so'm joriy etildi (1994-yil), davlat ramzlari (gerb, bayroq, madhiya) qabul qilindi, O'zbekiston Respublikasining Konstitutsiyasi ishlab chiqildi (1992-yil 8-dekabr) va yangi davlat boshqaruv tizimi shakllantirildi.","Qo'shni davlatlardagi fuqarolar urushi va beqarorlik fonida O'zbekiston tinchlik va barqarorlikni saqlab qolishga muvaffaq bo'ldi. Bu mamlakatning mustaqil rivojlanishi uchun muhim shart-sharoit yaratdi."]),("Taraqqiyot yo'lining asosiy tamoyillari",["O'zbekiston o'ziga xos taraqqiyot modelini ishlab chiqdi va uni amalga oshirishda beshta asosiy tamoyilga amal qildi: iqtisodiyotning siyosatdan ustunligi, davlatning bosh islohotchi ekanligi, qonun ustuvorligi, kuchli ijtimoiy siyosat va islohotlarni bosqichma-bosqich amalga oshirish.","Iqtisodiyotning siyosatdan ustunligi tamoyili — iqtisodiy masalalarni hal qilishda mafkuraviy yondashuvlardan voz kechish va amaliy natijaga yo'naltirilgan qarorlar qabul qilishni anglatadi. Davlatning bosh islohotchi ekanligi — o'tish davrida davlatning bozor iqtisodiyotiga o'tishni boshqarishi va tartibga solishini bildiradi.","Bosqichma-bosqich islohotlar strategiyasi mamlakatni keskin inqirozdan saqladi. Boshqa postsovyet mamlakatlardagi 'shok terapiya' o'rniga O'zbekiston asta-sekin, lekin barqaror o'zgarishlar yo'lini tanladi. Bu yondashuv ijtimoiy barqarorlikni saqlab qolish imkonini berdi."]),("Mustaqillikning xalqaro tan olinishi",["O'zbekiston mustaqilligi qisqa vaqt ichida jahon hamjamiyati tomonidan tan olindi. 1992-yilning boshiga kelib 130 dan ortiq davlat O'zbekistonni mustaqil davlat sifatida e'tirof etdi. Mamlakat BMT, YeHHT, MDH va boshqa xalqaro tashkilotlarga a'zo bo'ldi.","1992-yil 2-martda O'zbekiston Birlashgan Millatlar Tashkilotiga a'zo bo'ldi — bu mamlakatning xalqaro huquq subyekti sifatidagi maqomini mustahkamladi. Shuningdek, Jahon banki, Xalqaro valyuta fondi va boshqa moliyaviy tashkilotlar bilan hamkorlik o'rnatildi.","O'zbekiston mustaqillikning dastlabki yillaridayoq faol tashqi siyosat yuritib, ikki tomonlama diplomatik munosabatlar o'rnatdi, xalqaro shartnomalar imzoladi va mintaqaviy hamkorlikda faol qatnashdi. Bu mamlakatning xalqaro obro'sini mustahkamladi."])],})

TOPICS.append({"num":2,"title":"1991-1995-yillarda siyosiy va iqtisodiy islohotlar","reja":["Yangi davlat boshqaruv tizimining shakllanishi.","Konstitutsiyaning qabul qilinishi va huquqiy asos yaratish.","Iqtisodiy islohotlarning boshlang'ich bosqichi.","Xususiylashtirish va bozor munosabatlariga o'tish."],"sections":[("Yangi davlat boshqaruv tizimining shakllanishi",["Mustaqillikning dastlabki yillarida yangi davlat boshqaruv tizimi shakllantirila boshlandi. Prezidentlik boshqaruv shakli joriy etildi, Oliy Majlis (parlament) tashkil topdi, vazirlar mahkamasi qayta tuzildi va mahalliy hokimiyat organlari yangi tartibda ishlay boshladi.","Huquq-tartibot organlari, mudofaa tizimi va xavfsizlik xizmatlari milliy asosda qayta tashkil etildi. O'zbekiston qurolli kuchlari, ichki ishlar organlari va maxsus xizmatlar yangi davlat manfaatlarini himoya qilish uchun shakllantirild.","Mahalliy boshqaruv tizimida viloyat, tuman va shahar hokimliklari tashkil etildi. Fuqarolarning o'zini o'zi boshqarish organlari — mahalla institutining roli kuchaytirildi. Bu o'ziga xos demokratik boshqaruv shakli rivojlantirildi."]),("Konstitutsiyaning qabul qilinishi va huquqiy asos yaratish",["1992-yil 8-dekabrda O'zbekiston Respublikasining Konstitutsiyasi qabul qilindi. U mamlakatning asosiy qonuni sifatida davlat tuzumi, fuqarolar huquqlari va erkinliklari, davlat hokimiyati organlari tizimini belgilab berdi.","Konstitutsiyada inson huquqlari va erkinliklari oliy qadriyat sifatida e'tirof etildi. Demokratik, huquqiy va dunyoviy davlat qurish maqsad qilib qo'yildi. Hokimiyatning qonun chiqaruvchi, ijro etuvchi va sud tarmoqlariga bo'linishi mustahkamlandi.","Konstitutsiya asosida yangi qonunchilik tizimi shakllantirila boshlandi: fuqarolik kodeksi, jinoyat kodeksi, mehnat kodeksi va boshqa muhim qonunlar qabul qilindi. Bu huquqiy davlat qurishning amaliy qadamlari bo'ldi."]),("Iqtisodiy islohotlarning boshlang'ich bosqichi",["1991-1995-yillarda iqtisodiy islohotlarning asosiy yo'nalishi — rejali iqtisodiyotdan bozor iqtisodiyotiga bosqichma-bosqich o'tish edi. Bu davrda narxlarni erkinlashtirish, savdo tizimini isloh qilish va tadbirkorlikni rivojlantirish uchun shart-sharoitlar yaratildi.","1994-yilda milliy valyuta — so'm muomalaga kiritildi. Bu mamlakat mustaqil pul-kredit siyosati yuritishi uchun muhim qadam bo'ldi. Markaziy bank tashkil etildi va bank tizimi isloh qilina boshlandi.","Qishloq xo'jaligida islohotlar — yerdan foydalanish tartibini o'zgartirish, fermer xo'jaliklarini tashkil etish va dehqon xo'jaliklarini qo'llab-quvvatlash kabi yo'nalishlarda olib borildi. Kolxoz va sovxozlar bosqichma-bosqich tugatildi."]),("Xususiylashtirish va bozor munosabatlariga o'tish",["Xususiylashtirish — davlat mulkini xususiy mulkka o'tkazish jarayoni — iqtisodiy islohotlarning muhim yo'nalishi bo'ldi. Kichik xususiylashtirish (do'konlar, maishiy xizmat korxonalari) tezroq, katta xususiylashtirish (sanoat korxonalari) asta-sekin amalga oshirildi.","Tadbirkorlikni rivojlantirish uchun huquqiy baza yaratildi: 'Tadbirkorlik faoliyati erkinligining kafolatlari to'g'risida', 'Kichik va xususiy biznes to'g'risida' va boshqa qonunlar qabul qilindi. Soliq imtiyozlari va kreditlar berildi.","Bu davrda bozor infratuzilmasi shakllantirila boshlandi: birjalar, banklar, sug'urta kompaniyalari va investitsiya fondlari tashkil topdi. Xorijiy investitsiyalarni jalb qilish uchun qo'shma korxonalar tuzish rag'batlantirildi."])],})

TOPICS.append({"num":3,"title":"1996-2000-yillarda ijtimoiy va madaniy hayot","reja":["Ijtimoiy sohadagi islohotlar va aholini ijtimoiy himoyalash.","Ta'lim tizimini isloh qilish va kadrlar tayyorlash.","Sog'liqni saqlash tizimidagi o'zgarishlar.","Madaniy hayot va milliy qadriyatlarning tiklanishi."],"sections":[("Ijtimoiy sohadagi islohotlar va aholini ijtimoiy himoyalash",["1996-2000-yillarda ijtimoiy siyosat davlat siyosatining ustuvor yo'nalishlaridan biri bo'lib qoldi. Kam ta'minlangan oilalar, nogironlar, ko'p bolali oilalar va yolg'iz qariyalar uchun ijtimoiy yordam dasturlari joriy etildi.","Ish haqi, nafaqa va stipendiyalar bosqichma-bosqich oshirib borildi. Mahalla institutiga ijtimoiy yordam taqsimlash vazifalari berildi — bu yordam manzilli va adolatli bo'lishini ta'minladi. Mahalla fuqarolarga eng yaqin ijtimoiy himoya bo'g'ini sifatida ishladi.","Aholini ish bilan ta'minlash dasturlari amalga oshirildi: kichik biznes va hunarmandchilikni rag'batlantirish, kasbga o'qitish kurslari va yoshlar bandligini ta'minlash choralari ko'rildi."]),("Ta'lim tizimini isloh qilish va kadrlar tayyorlash",["1997-yilda 'Kadrlar tayyorlash milliy dasturi' va 'Ta'lim to'g'risida'gi qonun qabul qilindi. Bu hujjatlar ta'lim tizimini tubdan isloh qilishga asos bo'ldi. 9 yillik umumiy o'rta ta'lim va 3 yillik o'rta maxsus (kasb-hunar kollejlari va akademik litsey) ta'lim tizimi joriy etildi.","Mamlakatning barcha hududlarida yangi kasb-hunar kollejlari va akademik litseylar qurildi. Ular zamonaviy uskunalar bilan jihozlandi. Maqsad — har bir yoshga kasb berish va mehnat bozoriga tayyorlash edi.","Oliy ta'lim tizimi ham isloh qilindi: bakalavriat va magistratura bosqichlari joriy etildi, yangi universitetlar ochildi va xorijiy oliy ta'lim muassasalari bilan hamkorlik kengaytirildi. Chet elda o'qish uchun davlat grantalari ajratila boshlandi."]),("Sog'liqni saqlash tizimidagi o'zgarishlar",["Sog'liqni saqlash tizimida oilaviy poliklinikalar tarmog'i yaratildi — bu birlamchi tibbiy yordam xizmatini aholiga yaqinlashtirdi. Qishloq joylarda tibbiy punktlar qurildi va jihozlandi. Profilaktika va erta aniqlash ishlari kuchaytirildi.","Ona va bola salomatligini muhofaza qilish davlat siyosatining ustuvor yo'nalishiga aylandi. 'Sog'lom avlod uchun' va 'Sog'lom ona — sog'lom bola' dasturlari amalga oshirildi. Chaqaloq o'limi va ona o'limi ko'rsatkichlari sezilarli kamaydi.","Tibbiyot xodimlarini tayyorlash va malakasini oshirish tizimi yaxshilandi. Xorijiy mamlakatlar va xalqaro tashkilotlar bilan sog'liqni saqlash sohasida hamkorlik kengaytirildi."]),("Madaniy hayot va milliy qadriyatlarning tiklanishi",["Mustaqillik yillarida milliy tarix, adabiyot va san'atga bo'lgan munosabat tubdan o'zgardi. Avval taqiqlangan tarixiy shaxslar — Amir Temur, Bobur, Ulug'bek, Navoiy kabi buyuk ajdodlar xotirasi tiklandi, ularga haykallar o'rnatildi.","Milliy bayramlar tizimi shakllandi: Mustaqillik kuni, Navro'z, Xotira va qadrlaash kuni va boshqalar. Bu bayramlar xalq ruhiyatini mustahkamlash va milliy o'zlikni anglash uchun muhim ahamiyatga ega bo'ldi.","Madaniy meros obyektlari ta'mirlanib, saqlandi. Samarqand, Buxoro va Xiva shaharlaridagi tarixiy obidalar qayta tiklanib, YUNESKO ro'yxatiga kiritildi. Teatr, kino, musiqa va tasviriy san'at sohalarida yangi asarlar yaratildi."])],})

TOPICS.append({"num":4,"title":"2001-2005-yillarda tashkilot siyosati va iqtisodiy strategiyasi","reja":["2001-2005-yillar davlat dasturlari va strategik maqsadlar.","Sanoat va qishloq xo'jaligini modernizatsiya qilish.","Kichik biznes va xususiy sektorning rivojlanishi.","Tashqi iqtisodiy aloqalar va investitsiyalar."],"sections":[("2001-2005-yillar davlat dasturlari va strategik maqsadlar",["2001-2005-yillarda O'zbekiston islohotlarning yangi bosqichiga o'tdi. Bu davrning asosiy maqsadi — iqtisodiy o'sishni tezlashtirish, ishlab chiqarishni modernizatsiya qilish va aholining turmush darajasini oshirish edi.","Bu davrda bir qator maqsadli dasturlar qabul qilindi: sanoatni rivojlantirish, qishloq xo'jaligini isloh qilish, kichik biznesni qo'llab-quvvatlash va hududlarni kompleks rivojlantirish dasturlari. Har bir dastur aniq maqsadlar va amalga oshirish mexanizmlarini o'z ichiga oldi.","Mamlakat iqtisodiyoti barqaror o'sish sur'atlarini namoyish etdi: yalpi ichki mahsulot yiliga o'rtacha 4-5 foizga o'sdi, inflyatsiya nazorat ostida saqlandi va tashqi qarz yuklamasi boshqariladigan darajada bo'ldi."]),("Sanoat va qishloq xo'jaligini modernizatsiya qilish",["Sanoatda modernizatsiya va diversifikatsiya siyosati olib borildi: yangi tarmoqlar (avtomobilsozlik, elektrotexnika, farmatsevtika) yaratildi, mavjud korxonalar texnik qayta jihozlandi va mahsulot sifati oshirildi.","O'zbekistonda avtomobilsozlik sanoati rivojlandi — 'UzDaewoo' (keyinchalik GM Uzbekistan) zavodi faoliyat yuritib, minglab ish o'rinlari yaratildi. Mamlakat avtomobil eksport qiluvchi davlatga aylandi.","Qishloq xo'jaligida fermer xo'jaliklari asosiy ishlab chiqaruvchiga aylandi. Paxta yakkahokimligidan qochib, bog'dorchilik, sabzavotchilik va chorvachilikni rivojlantirish siyosati olib borildi. Suvdan foydalanish samaradorligi oshirildi."]),("Kichik biznes va xususiy sektorning rivojlanishi",["2001-2005-yillarda kichik biznes va xususiy tadbirkorlik iqtisodiyotning tarkibiy qismiga aylandi. YAIMdagi ulushi sezilarli oshdi. Tadbirkorlar uchun soliq imtiyozlari, arzon kreditlar va boshqa rag'batlantirish choralari ko'rildi.","Tadbirkorlikni rivojlantirish infratuzilmasi kengaytirildi: biznes-inkubatorlar, tadbirkorlarni qo'llab-quvvatlash markazlari va mikrokredit tashkilotlari tashkil etildi. Huquqiy himoya mexanizmlari kuchaytirildi — tadbirkorlar huquqlarini himoya qilish kafolatlandi.","Xususiy sektor ish bilan ta'minlashning asosiy manbaiga aylandi: yangi ish o'rinlarining aksariyati kichik biznes va xususiy korxonalarda yaratildi. Bu ijtimoiy barqarorlikni ta'minlash va kambag'allikni kamaytirishda muhim rol o'ynadi."]),("Tashqi iqtisodiy aloqalar va investitsiyalar",["O'zbekiston tashqi iqtisodiy aloqalarini faol rivojlantirdi: ko'plab mamlakatlar bilan savdo-iqtisodiy hamkorlik shartnomalarilari imzolandi. Eksport hajmi oshirildi va eksport tarkibi diversifikatsiya qilindi — xom ashyo ulushi kamaytirildi.","Xorijiy investitsiyalarni jalb qilish siyosati kuchaytirildi: erkin iqtisodiy zonalar tashkil etildi, investitsion muhit yaxshilandi va xorijiy investorlarga kafolatlar berildi. Yaponiya, Koreya, Germaniya va boshqa mamlakatlar yirik loyihalarda ishtirok etdi.","Xalqaro moliyaviy tashkilotlar (Jahon banki, ADB, YEIB) bilan hamkorlik kengaytirildi. Ular infratuzilma, ta'lim, sog'liqni saqlash va qishloq xo'jaligi sohalarida loyihalarni moliyalashtirishda qatnashdi."])],})

TOPICS.append({"num":5,"title":"Yangilanayotgan O'zbekiston","reja":["2005-2010-yillar: islohotlarning yangi bosqichi.","Iqtisodiy modernizatsiya va innovatsion rivojlanish.","Ijtimoiy sohadagi yutuqlar va muammolar.","O'zbekistonning xalqaro mavqeyi."],"sections":[("2005-2010-yillar: islohotlarning yangi bosqichi",["2005-2010-yillarda O'zbekiston islohotlarning chuqurlashuvi bosqichiga kirdi. Bu davrda bozor iqtisodiyotini mustahkamlash, demokratik institutlarni rivojlantirish va fuqarolik jamiyatini shakllantirish yo'nalishlarida muhim qadamlar tashlandi.","Parlament islohoti amalga oshirildi: ikki palatali Oliy Majlis (Senat va Qonunchilik palatasi) tashkil topdi. Bu qonun chiqarish jarayonini takomillashtirdi va mintaqalar manfaatlarini yaxshiroq ifodalash imkonini berdi.","Sud-huquq tizimida islohotlar davom ettirildi: sudlar mustaqilligi kuchaytirildi, advokatura instituti rivojlantirildi va inson huquqlarini himoyalash mexanizmlari takomillashtirildi."]),("Iqtisodiy modernizatsiya va innovatsion rivojlanish",["Bu davrda iqtisodiy siyosatning asosiy yo'nalishi — ishlab chiqarishni texnik va texnologik jihatdan yangilash, raqobatbardosh mahsulot ishlab chiqarish va innovatsion iqtisodiyotga o'tish edi.","Energetika sohasida mustaqillikka erishish maqsadida neft va gazni qayta ishlash quvvatlari oshirildi, yangi energiya manbalari izlandi. Transport infratuzilmasi rivojlantirildi: yangi temir yo'l va avtomobil yo'llari qurildi.","Axborot texnologiyalari sohasiga alohida e'tibor qaratildi: internet tarqalishi kengaydi, elektron hukumat tizimi joriy etila boshlandi va raqamli iqtisodiyot elementlari paydo bo'ldi."]),("Ijtimoiy sohadagi yutuqlar va muammolar",["Ijtimoiy sohada sezilarli yutuqlarga erishildi: o'rtacha umr ko'rish davomiyligi oshdi, savodxonlik darajasi yuqori saqlanib qoldi, bolalar o'limi kamaydi va aholining turmush darajasi yaxshilandi.","Biroq muammolar ham mavjud edi: ishsizlik (ayniqsa yoshlar orasida), mintaqalar orasidagi rivojlanish farqlari, sog'liqni saqlash va ta'lim sifatida hali yetarli darajaga erishilmaganligi va mehnat migratsiyasining kuchayishi.","Davlat bu muammolarni hal qilish uchun maqsadli dasturlar qabul qildi: yoshlarni ish bilan ta'minlash, qishloq infratuzilmasini rivojlantirish va ijtimoiy xizmatlar sifatini oshirish dasturlari amalga oshirildi."]),("O'zbekistonning xalqaro mavqeyi",["O'zbekiston xalqaro munosabatlarda mustaqil va faol siyosat yuritdi. Mamlakat hech qanday harbiy blokka qo'shilmaslik, boshqa davlatlar ichki ishlariga aralashmaslik va muammolarni tinch yo'l bilan hal qilish tamoyillariga amal qildi.","Mintaqaviy hamkorlik rivojlantirildi: Markaziy Osiyo mamlakatlari bilan chegaraviy masalalar, suv resurslari va transport aloqalari bo'yicha muzokaralar olib borildi. Terrorizmga qarshi kurashda xalqaro hamkorlik kuchaytirildi.","O'zbekiston BMT, SHHTva boshqa xalqaro tashkilotlar doirasida faol qatnashdi. Mamlakat tashabbusi bilan mintaqaviy xavfsizlik, ekologiya va yadro qurolsizlanish masalalarida muhim qarorlar qabul qilindi."])],})

print("1-5 topics added")

TOPICS.append({"num":6,"title":"2011-2015-yillarda modernizatsiya va yangilanish","reja":["Iqtisodiyotni modernizatsiyalash strategiyasi.","Sanoat va infratuzilma loyihalari.","Ijtimoiy sohada yangilanishlar.","Ta'lim va fan sohasidagi islohotlar."],"sections":[("Iqtisodiyotni modernizatsiyalash strategiyasi",["2011-2015-yillarda O'zbekiston iqtisodiyotini modernizatsiyalash va diversifikatsiyalash siyosati yanada kuchaytirildi. Asosiy maqsad — xom ashyo eksportiga bog'liqlikni kamaytirish, tayyor mahsulot ishlab chiqarishni ko'paytirish va yuqori qo'shimcha qiymatli tarmoqlarni rivojlantirish edi.","Bu davrda YaIM barqaror o'sishni davom ettirdi — yiliga 7-8 foiz. Inflyatsiya nisbatan nazorat ostida saqlandi. Sanoat ishlab chiqarishi hajmi sezilarli oshdi va eksport tarkibida tayyor mahsulot ulushi ko'paydi.","Investitsion dasturlar doirasida yirik loyihalar amalga oshirildi: Ustyurtdagi gaz-kimyo kompleksi, Qo'ng'irotdagi soda zavodi, Toshkent issiqlik elektr stansiyasining modernizatsiyasi va boshqa strategik obyektlar qurildi."]),("Sanoat va infratuzilma loyihalari",["Sanoatda yangi tarmoqlar rivojlantirildi: neft-kimyo, farmatsevtika, qurilish materiallari, oziq-ovqat sanoati va yengil sanoat korxonalari zamonaviy texnologiyalar asosida qayta jihozlandi yoki yangi qurildi.","Transport infratuzilmasi sezilarli rivojlandi: Toshkent-Samarqand yuqori tezlikli temir yo'li (Afrosiyob) ishga tushirildi, yangi aeroport terminallari qurildi va avtomobil yo'llari sifati yaxshilandi. Bu mamlakat ichidagi va xalqaro aloqalarni mustahkamladi.","Energetika sohasida yangi quvvatlar yaratildi: quyosh va shamol energetikasini rivojlantirish boshlandi. Gaz va neftni qayta ishlash quvvatlari oshirildi. Energiya samaradorligini oshirish dasturlari amalga oshirildi."]),("Ijtimoiy sohada yangilanishlar",["Aholining turmush darajasini oshirish maqsadida ish haqi, nafaqa va stipendiyalar muntazam ko'tarib borildi. Uy-joy qurilishi dasturlari amalga oshirildi — qishloq joylarda arzon uyjoy qurilishi kengaytirildi.","Kommunal infratuzilma yaxshilandi: ichimlik suvi ta'minoti, kanalizatsiya va gaz ta'minoti tarmoqlari kengaytirildi. Qishloq joylardagi turmush sharoitlari shaharga yaqinlashtirildi.","Yoshlar siyosati kuchaytirildi: yoshlarni qo'llab-quvvatlash dasturlari, sport va sog'lom turmush tarzi rag'batlantirildi. Xalqaro sport musobaqalarida O'zbekiston sportchilari yuqori natijalar ko'rsatdi."]),("Ta'lim va fan sohasidagi islohotlar",["Ta'lim tizimi takomillashtirildi: o'quv dasturlari yangilandi, zamonaviy o'quv qo'llanmalari yaratildi va axborot texnologiyalaridan foydalanish kengaytirildi. Xorijiy universitetlar filiallari ochildi.","Ilm-fan sohasida innovatsion tadqiqotlar rag'batlantirildi: ilmiy grantlar tizimi joriy etildi, yosh olimlarni qo'llab-quvvatlash mexanizmlari kuchaytirildi va xalqaro ilmiy hamkorlik kengaytirildi.","Kasb-hunar ta'limi tizimi takomillashtirildi: ish beruvchilar ehtiyojlariga mos kadrlar tayyorlash, amaliy ko'nikmalarni kuchaytirish va ta'lim-ishlab chiqarish integratsiyasi yo'nalishlarida ishlar olib borildi."])],})

TOPICS.append({"num":7,"title":"2016-2020-yillarda siyosiy va iqtisodiy yangilanish","reja":["2016-yil — yangi siyosiy davr boshlanishi.","Harakatlar strategiyasi va beshta ustuvor yo'nalish.","Iqtisodiy liberallashtirish va ochiq siyosat.","Demokratik islohotlar va fuqarolik jamiyati."],"sections":[("2016-yil — yangi siyosiy davr boshlanishi",["2016-yil sentyabrida Shavkat Mirziyoyev O'zbekiston Respublikasi Prezidenti etib saylandi. Bu mamlakat tarixida yangi islohot davri boshlanishini belgiladi. Yangi rahbariyat ochiq muloqot, tanqidiy yondashuv va tezkor islohotlar siyosatini e'lon qildi.","Dastlabki qadamlar: virtual qabulxonalar tashkil etildi, xalq murojaatlari tizimi yo'lga qo'yildi, byurokratik to'siqlar kamaytirildi va fuqarolar davlat organlari bilan bevosita muloqot qilish imkoniyatiga ega bo'ldi.","Tashqi siyosatda ham keskin burilish yuz berdi: qo'shni davlatlar bilan munosabatlar sezilarli yaxshilandi, chegara masalalari hal qilindi va mintaqaviy hamkorlik yangi darajaga ko'tarildi."]),("Harakatlar strategiyasi va beshta ustuvor yo'nalish",["2017-2021-yillarga mo'ljallangan O'zbekiston Respublikasini rivojlantirishning beshta ustuvor yo'nalishi bo'yicha Harakatlar strategiyasi qabul qilindi. Bu hujjat islohotlarning batafsil yo'l xaritasi bo'lib, mamlakatning barcha sohalarini qamrab oldi.","Beshta ustuvor yo'nalish: davlat va jamiyat qurilishini demokratlashtirish; sud-huquq tizimini isloh qilish; iqtisodiyotni rivojlantirish va liberallashtirish; ijtimoiy sohani rivojlantirish; xavfsizlik, millatlararo totuvlik va tashqi siyosat.","Har bir yo'nalish bo'yicha aniq maqsadlar, ko'rsatkichlar va amalga oshirish mexanizmlari belgilandi. Har yili alohida nom bilan ataldi: Xalq bilan muloqot yili, Faol tadbirkorlik yili, Investitsiyalar yili va boshqalar."]),("Iqtisodiy liberallashtirish va ochiq siyosat",["2017-yil sentyabrida valyuta bozori liberallashtirildi — so'm kursi erkin bozor mexanizmi asosida belgilanadigan bo'ldi. Bu qaror iqtisodiy islohotlarning eng muhim qadamlaridan biri bo'ldi va xorijiy investorlar ishonchini oshirdi.","Soliq islohoti amalga oshirildi: soliq turlari soni kamaytirildi, stavkalar pasaytirildi va soliq ma'muriyati soddal ashtirildi. Tadbirkorlik uchun muhit sezilarli yaxshilandi: litsenziyalar va ruxsatnomalar soni keskin qisqartirildi.","Davlat korxonalarini xususiylashtirish tezlashtirildi, raqobat muhiti kuchaytirildi va monopoliyaga qarshi siyosat olib borildi. Bank tizimi isloh qilindi: xususiy banklar faoliyati kengaydi va raqamli bank xizmatlari rivojlandi."]),("Demokratik islohotlar va fuqarolik jamiyati",["Ommaviy axborot vositalari erkinligi kengaytirildi: blokirovka qilingan veb-saytlar ochildi, jurnalistlar faoliyati uchun sharoitlar yaxshilandi va axborot olish erkinligi kuchaytirildi.","Nodavlat notijorat tashkilotlar faoliyati uchun shart-sharoitlar yaratildi. Fuqarolik jamiyati institutlari rivojlantirildi: jamoatchilik nazorati kuchaytirildi, parlament ustidan jamoatchilik nazorati mexanizmlari joriy etildi.","Inson huquqlari sohasida muhim qadamlar tashlandi: majburiy mehnatga qarshi kurash kuchaytirildi, hibsga olish muddatlari qisqartirildi va sudlov tizimida adolat ta'minlash mexanizmlari takomillashtirildi."])],})

TOPICS.append({"num":8,"title":"2021-yil — hozirgi davr O'zbekiston","reja":["Yangi O'zbekiston — 2022-2026 strategiyasi.","Konstitutsiya islohoti va yangi tahriri.","Iqtisodiy islohotlarning davomi.","Ijtimoiy himoya va fuqarolar farovonligi."],"sections":[("Yangi O'zbekiston — 2022-2026 strategiyasi",["2022-yilda O'zbekiston Respublikasini 2022-2026-yillarda rivojlantirishning Yangi O'zbekiston taraqqiyot strategiyasi qabul qilindi. U avvalgi Harakatlar strategiyasini davom ettirdi va yanada chuqurroq islohotlarni ko'zda tutdi.","Strategiyaning asosiy maqsadlari: inson qadr-qimmatini ta'minlash, iqtisodiy o'sishni tezlashtirish, adolatli ijtimoiy siyosat yuritish va xavfsiz muhit yaratish. Har bir maqsad bo'yicha aniq ko'rsatkichlar belgilandi.","Har yilga alohida dastur ishlab chiqildi va hisob-kitob qilindi. Xalq bilan ochiq muloqot an'anasi davom ettirildi — Prezidentning xalqqa murojaatlari va virtual qabulxonalar faoliyati kengaytirildi."]),("Konstitutsiya islohoti va yangi tahriri",["2023-yil 30-aprelda o'tkazilgan referendum natijasida O'zbekiston Respublikasining yangilangan Konstitutsiyasi qabul qilindi. Fuqarolarning 90 foizdan ortig'i yangi tahrirni qo'llab-quvvatladi.","Yangilangan Konstitutsiyada inson huquqlari va erkinliklari to'liqroq mustahkamlandi, ijtimoiy davlat tamoyillari kuchaytirildi va demokratik institutlar roli oshirildi. O'lim jazosi butunlay bekor qilindi.","Konstitutsiyaga yangi normalar kiritildi: ekologik huquqlar, raqamli huquqlar, bolalar huquqlari va boshqa zamonaviy masalalar aks ettirildi. Bu O'zbekistonning zamonaviy demokratik davlat sifatidagi rivojlanishini mustahkamladi."]),("Iqtisodiy islohotlarning davomi",["2021-yildan boshlab iqtisodiy islohotlar yanada chuqurlashtirildi: davlat korxonalarini xususiylashtirish tezlashdi, xorijiy investitsiyalar oqimi ko'paydi va yangi iqtisodiy zonalar tashkil etildi.","Raqamli iqtisodiyot jadal rivojlandi: raqamli to'lov tizimlari kengaydi, davlat xizmatlarining aksariyati onlayn shaklga o'tkazildi va IT sektorini rivojlantirish dasturi amalga oshirildi. Yashil iqtisodiyot va barqaror rivojlanish siyosati kuchaytirildi.","Jahon banki va boshqa xalqaro tashkilotlar O'zbekiston islohotlarini yuqori baholadi. Mamlakat xalqaro kredit reytinglari yaxshilandi va xorijiy investorlar ishonchi oshdi."]),("Ijtimoiy himoya va fuqarolar farovonligi",["Kambag'allikni qisqartirish davlat siyosatining ustuvor maqsadiga aylandi. Ijtimoiy reestr tizimi joriy etildi — bu manzilli ijtimoiy yordamni ta'minlash imkonini berdi. Kam ta'minlangan oilalarga moddiy yordam oshirildi.","Uy-joy muammosini hal qilish uchun arzon ipoteka dasturlari joriy etildi, yangi turar-joy massivlari qurildi va kommunal infratuzilma yaxshilandi. Aholining turmush sifati ko'rsatkichlari yaxshilandi.","Ta'lim va sog'liqni saqlash sohalariga ajratiladigan byudjet mablag'lari sezilarli oshirildi. Xususiy ta'lim va tibbiyot muassasalari faoliyati kengaydi. Fuqarolarning sifatli xizmatlarga kirishish imkoniyati oshdi."])],})

TOPICS.append({"num":9,"title":"Sh. M. Mirziyoyev rahbarligida O'zbekistonda amalga oshirilayotgan islohotlar","reja":["Islohotlarning asosiy yo'nalishlari va metodologiyasi.","Ochiq tashqi siyosat va mintaqaviy hamkorlik.","Iqtisodiy erkinlashtirish va investitsion muhit.","Ijtimoiy adolat va xalq manfaati siyosati."],"sections":[("Islohotlarning asosiy yo'nalishlari va metodologiyasi",["Shavkat Mirziyoyev rahbarligidagi islohotlar ikki asosiy tamoyilga qurilgan: birinchisi — xalq davlat organlariga emas, davlat organlari xalqqa xizmat qilishi kerak; ikkinchisi — inson manfaatlari har qanday islohotning markazida turishi kerak.","Islohotlar metodologiyasi: muammolarni ochiq tan olish, xalq fikriga tayanish, ilmiy asoslangan yechimlar ishlab chiqish, xalqaro tajribadan foydalanish va natijalarni muntazam nazorat qilish. Har bir soha bo'yicha aniq ko'rsatkichlar va mas'ul shaxslar belgilangan.","Islohotlarning o'ziga xos xususiyati — ularning tezligi va keng qamrovliligi. Bir necha yil ichida deyarli barcha sohalarda — iqtisodiyot, ta'lim, sog'liqni saqlash, sud tizimi, tashqi siyosat — tub o'zgarishlar amalga oshirildi."]),("Ochiq tashqi siyosat va mintaqaviy hamkorlik",["Tashqi siyosatda tubdan o'zgarish yuz berdi: Markaziy Osiyo mamlakatlari bilan munosabatlar sezilarli yaxshilandi. Qirg'iziston, Tojikiston va Qozog'iston bilan chegara masalalari hal qilindi, transport aloqalari tiklandi va savdo hajmi oshdi.","Afg'oniston masalasida O'zbekiston faol vositachilik pozitsiyasini egalladi: gumanitar yordam ko'rsatdi, transport loyihalarini taklif qildi va tinchlik jarayoniga hissa qo'shdi. Bu O'zbekistonning mintaqaviy liderlik rolini kuchaytirdi.","Yevropa Ittifoqi, AQSh, Xitoy, Rossiya, Turkiya va boshqa mamlakatlar bilan strategik sherikchilik rivojlantirildi. O'zbekiston Yevropa Ittifoqi bilan kengaytirilgan sherikchilik va hamkorlik bitimini imzoladi."]),("Iqtisodiy erkinlashtirish va investitsion muhit",["Biznes yuritish sharoitlari tubdan yaxshilandi: litsenziya va ruxsatnomalar soni keskin kamaytirildi, ro'yxatga olish jarayoni soddal ashtirildi va tadbirkorlar huquqlari kuchli himoya qilindi. Doing Business reytingida O'zbekiston pozitsiyasi yaxshilandi.","Xorijiy investitsiyalar oqimi ko'p barobar oshdi: O'zbekiston xalqaro investorlar uchun jozibali mamlakat sifatida tan olindi. Xususan, tog'-kon sanoati, energetika, kimyo sanoati va IT sohasiga katta investitsiyalar jalb qilindi.","Erkin iqtisodiy zonalar tarmog'i kengaytirildi: Navoiy, Jizzax, Angren va boshqa hududlarda maxsus iqtisodiy zonalar faoliyat yuritmoqda. Ular investorlarga soliq imtiyozlari, infratuzilma va boshqa qulayliklarni taqdim etadi."]),("Ijtimoiy adolat va xalq manfaati siyosati",["Ijtimoiy siyosatda insonparvarlik tamoyili ustuvor qo'yildi: majburiy mehnat bekor qilindi, bolalar mehnati to'liq bartaraf etildi va inson qadr-qimmatini himoyalash kuchaytirildi.","Kambag'allikni qisqartirish bo'yicha aniq maqsadlar belgilandi va amaliy choralar ko'rildi: har bir mahallada tadbirkorlikni rivojlantirish, uy-joy qurilishi, infratuzilma yaxshilash va bandlikni ta'minlash ishlari olib borildi.","Ayollar huquqlari va gender tenglik masalalariga alohida e'tibor qaratildi: ayollarning siyosiy ishtirokini kuchaytirish, iqtisodiy mustaqilligini ta'minlash va oilaviy zo'ravonlikka qarshi qonunchilik kuchaytirildi."])],})

TOPICS.append({"num":10,"title":"Yangi O'zbekistonda xalqchil va insonparvar davlat qurish","reja":["Xalqchil davlat tushunchasi va uning tamoyillari.","Inson qadr-qimmatini ta'minlash siyosati.","Fuqarolar huquqlari va erkinliklarining kafolatlari.","Yangi O'zbekiston kelajagi va maqsadlari."],"sections":[("Xalqchil davlat tushunchasi va uning tamoyillari",["Xalqchil (xalqqa xizmat qiluvchi) davlat — bu davlat organlarining asosiy maqsadi fuqarolar manfaatlariga xizmat qilish bo'lgan boshqaruv modelidir. Yangi O'zbekistonda bu tamoyil davlat siyosatining asosiy yo'nalishiga aylandi.","Xalqchil davlatning tamoyillari: davlat xizmatchilari xalqqa hisobot berishi, fuqarolar muammolarining tezkor hal qilinishi, davlat xizmatlarining sifatli va qulay bo'lishi, byurokratiyaning kamaytirilishi va shaffoflik ta'minlanishi.","Amaliy qadamlar: xalq qabulxonalari, Prezidentning virtual qabulxonasi, mahalla raislari faoliyatining kuchaytirilishi, fuqarolar murojaatlari tizimining avtomatlashtirilishi va davlat organlarining hisobdorligi oshirilishi."]),("Inson qadr-qimmatini ta'minlash siyosati",["Yangilangan Konstitutsiyada inson qadr-qimmati oliy qadriyat sifatida mustahkamlandi. Davlat har bir fuqaroning sha'ni va huquqlarini himoyalash majburiyatini o'z zimmasiga oldi. Bu tamoyil barcha qonunlar va siyosatlarda aks ettirildi.","Amaliy choralar: hibsxona va qamoqxonalardagi sharoitlar yaxshilandi, qiynoqqa qarshi kurash kuchaytirildi, inson huquqlari bo'yicha milliy strategiya qabul qilindi va xalqaro shartnomalar ratifikatsiya qilindi.","Ijtimoiy zaif guruhlar — nogironlar, yolg'iz qariyalar, yetim bolalar va boshqa himoyaga muhtoj shaxslar uchun maxsus dasturlar ishlab chiqildi. Ularning jamiyatda to'liq ishtirok etishi uchun sharoitlar yaratildi."]),("Fuqarolar huquqlari va erkinliklarining kafolatlari",["Yangi O'zbekistonda so'z erkinligi, axborot olish erkinligi, yig'ilishlar erkinligi va vijdon erkinligi kuchaytirildi. OAV erkinligi indeksida mamlakat ko'rsatkichlari yaxshilandi. Ijtimoiy tarmoqlarda ochiq muhokamalar kengaydi.","Sudlov tizimida adolat ta'minlash mexanizmlari takomillashtirildi: sudlar mustaqilligi kuchaytirildi, advokatura instituti rivojlantirildi va jabrlanuvchilar huquqlari himoyasi yaxshilandi. Huquqiy yordam olish imkoniyati kengaytirildi.","Fuqarolar o'zini o'zi boshqarish — mahalla institutining roli yanada kuchaytirildi. Mahalla budjetlari tashkil etildi, mahalla raislari bevosita fuqarolar tomonidan saylanadigan bo'ldi va ularning vakolatlari kengaytirildi."]),("Yangi O'zbekiston kelajagi va maqsadlari",["Yangi O'zbekistonning strategik maqsadi — 2030-yilga borib o'rta daromadli mamlakatlar qatoriga kirish. Buning uchun iqtisodiy o'sishni yiliga 6-7 foiz darajasida saqlab turish, kambag'allikni ikki barobar kamaytirish va inson kapitaliga investitsiyalarni oshirish rejalashtirilgan.","Raqamli transformatsiya — kelajak O'zbekistonining muhim yo'nalishi: sun'iy intellekt, raqamli iqtisodiyot, elektron hukumat va innovatsion ta'lim rivojlantiriladi. 2030-yilga borib YAIMda raqamli iqtisodiyot ulushi sezilarli oshishi kutilmoqda.","Yashil iqtisodiyot va barqaror rivojlanish — muhim strategik yo'nalish: qayta tiklanadigan energiya manbalarini rivojlantirish, ekologik muammolarni hal qilish va iqlim o'zgarishiga moslashish choralari ko'rilmoqda. Yangi O'zbekiston — zamonaviy, ochiq va taraqqiy etgan davlat bo'lish yo'lida."])],})

